import os
import json
import requests
from datetime import datetime
from fastapi import FastAPI, Request
from fastapi.responses import HTMLResponse
from fastapi.staticfiles import StaticFiles
import uvicorn
import re
from urllib.parse import urljoin

app = FastAPI()

# Serve static files
try:
    app.mount("/static", StaticFiles(directory="static"), name="static")
except:
    pass

EBAY_STORE_URL = "https://www.ebay.com/str/electroroomlaptopparts"
MARKUP_PERCENTAGE = 0.30
SERPER_API_KEY = os.environ.get("SERPER_API_KEY", "")

def scrape_laptop_listings():
    """Scrape laptop listings from Electro Room eBay store"""
    try:
        # Use Serper API to search the specific eBay store
        if SERPER_API_KEY:
            response = requests.post(
                "https://google.serper.dev/shopping",
                headers={"X-API-KEY": SERPER_API_KEY},
                json={
                    "q": "site:ebay.com laptop electro room",
                    "num": 15,
                    "gl": "us"
                },
                timeout=10
            )

            if response.status_code == 200:
                data = response.json()
                laptops = []

                for item in data.get("shopping", [])[:15]:
                    # Extract price and apply markup
                    price_str = item.get("price", "$0")
                    price_match = re.search(r'\$?([\d,]+\.?\d*)', price_str)
                    if price_match:
                        original_price = float(price_match.group(1).replace(',', ''))
                        marked_up_price = original_price * (1 + MARKUP_PERCENTAGE)

                        laptop = {
                            "title": item.get("title", "Laptop"),
                            "price": f"${marked_up_price:.0f}",
                            "original_price": f"${original_price:.0f}",
                            "image": item.get("imageUrl", "/static/laptop-placeholder.jpg"),
                            "link": item.get("link", "#"),
                            "source": item.get("source", "eBay")
                        }

                        # Only include if it looks like a laptop
                        title_lower = laptop["title"].lower()
                        if any(word in title_lower for word in ['laptop', 'notebook', 'thinkpad', 'dell', 'hp', 'lenovo', 'macbook']):
                            laptops.append(laptop)

                if laptops:
                    return laptops[:12]  # Limit to 12 for clean grid

    except Exception as e:
        print(f"Scraping failed: {e}")

    # Fallback to mock data
    return load_fallback_data()

def load_fallback_data():
    """Load fallback laptop data if scraping fails"""
    try:
        with open('data/fallback.json', 'r') as f:
            return json.load(f)
    except:
        # Ultimate fallback - hardcoded data
        return [
            {
                "title": "Dell Latitude 7420 - Intel i7, 16GB RAM, 512GB SSD",
                "price": "$649",
                "original_price": "$499",
                "image": "https://images.unsplash.com/photo-1496181133206-80ce9b88a853?w=300",
                "link": "#",
                "source": "eBay"
